function generateProductVariants(): SeedProduct[] {
  const variants: SeedProduct[] = []
  const brands = ['Mamaearth', 'WOW', 'Plum', 'Minimalist', 'Dot & Key', 'The Derma Co', 'Neutrogena', 'Lakme']
  const templates = [
    { base: 'Vitamin C', category: 'Face Care', price: 399, image: 'https://images.unsplash.com/photo-1620916566398-39f1143ab7be?w=800&q=80' },
    { base: 'Niacinamide', category: 'Face Care', price: 449, image: 'https://images.unsplash.com/photo-1617897903246-719242758050?w=800&q=80' },
    { base: 'Hyaluronic Acid', category: 'Face Care', price: 499, image: 'https://images.unsplash.com/photo-1612817288484-6f916006741a?w=800&q=80' },
    { base: 'Salicylic Acid', category: 'Acne Care', price: 549, image: 'https://images.unsplash.com/photo-1601049676869-702ea24cfd58?w=800&q=80' },
    { base: 'Retinol', category: 'Anti-Aging', price: 849, image: 'https://images.unsplash.com/photo-1598440947619-2c35fc9aa908?w=800&q=80' },
    { base: 'Onion', category: 'Hair Care', price: 399, image: 'https://images.unsplash.com/photo-1526045612212-70caf35c14df?w=800&q=80' },
    { base: 'Keratin', category: 'Hair Care', price: 499, image: 'https://images.unsplash.com/photo-1559056199-641a0ac8b55e?w=800&q=80' },
    { base: 'Shea Butter', category: 'Body Care', price: 349, image: 'https://images.unsplash.com/photo-1608248543803-ba4f8c70ae0b?w=800&q=80' },
    { base: 'Coffee', category: 'Body Care', price: 299, image: 'https://images.unsplash.com/photo-1631203977699-14c23e0d7db4?w=800&q=80' },
    { base: 'SPF 50', category: 'Sun Care', price: 449, image: 'https://images.unsplash.com/photo-1625772452888-c5e66f998f57?w=800&q=80' },
  ]
  const productTypes: Record<string, string[]> = {
    'Face Care': ['Serum', 'Cream', 'Gel', 'Toner', 'Face Wash', 'Mask'],
    'Hair Care': ['Shampoo', 'Conditioner', 'Hair Oil', 'Hair Mask', 'Serum'],
    'Body Care': ['Body Lotion', 'Body Wash', 'Body Scrub', 'Body Butter'],
    'Acne Care': ['Serum', 'Gel', 'Face Wash', 'Spot Treatment'],
    'Anti-Aging': ['Serum', 'Night Cream', 'Day Cream', 'Eye Cream'],
    'Sun Care': ['Sunscreen SPF50', 'Sunscreen SPF30', 'Tinted Sunscreen', 'After-Sun Gel'],
  }

  for (const template of templates) {
    const types = productTypes[template.category]
    for (const brand of brands) {
      for (const type of types) {
        const index = variants.length
        const price = template.price + (index % 5) * 25
        variants.push({
          name: `${template.base} ${type} ${index + 1}`,
          brand,
          category: template.category,
          price,
          originalPrice: Math.round(price * 1.15),
          discount: [10, 12, 14, 15, 17, 20][index % 6],
          rating: Number((3.8 + (index % 11) / 10).toFixed(1)),
          reviewCount: 200 + ((index * 137) % 3000),
          image: template.image,
          description: `${brand}'s ${template.base} ${type} for targeted skincare concerns. Formulated with active ingredients and suitable for a daily routine.`,
          ingredients: `${template.base} Extract, Hyaluronic Acid, Glycerin, Niacinamide, Allantoin`,
          howToUse: 'Apply as directed after cleansing. Follow with moisturizer and SPF in the morning.',
          inStock: index % 10 !== 0,
          stockCount: 20 + ((index * 17) % 200),
          tags: [template.base.toLowerCase().replace(/ /g, '-'), type.toLowerCase().replace(/ /g, '-'), template.category.toLowerCase().replace(/ /g, '-')],
        })
        if (variants.length >= 180) return variants
      }
    }
  }

  return variants
}

export const seedProducts: SeedProduct[] = [
  ...PRODUCTS,
  ...EXTRA_FACE,
  ...EXTRA_HAIR,
  ...EXTRA_BODY,
  ...PRODUCTS_BATCH_2,
  ...generateProductVariants(),
]

